create table users ( id uuid references auth.users on delete cascade primary key, email text not null, username text unique not null, display_name text, avatar_url text, bio text, native_language text default 'en', learning_languages text[] default '{}', total_xp integer default 0, current_level integer default 1, streak_days integer default 0, subscription_tier text default 'free', subscription_expiry timestamptz, is_premium boolean default false, is_active boolean default true, privacy_level text default 'public', total_games_played integer default 0, total_games_won integer default 0, total_friends integer default 0, rank integer default 0, country text, last_active_at timestamptz, achievements text[], settings jsonb, created_at timestamptz default now(), updated_at timestamptz default now() ); create table competitions ( id uuid default uuid_generate_v4() primary key, host_id uuid references users(id) not null, host_name text not null, host_avatar_url text, title text not null, description text, game_type text not null, language text not null, difficulty text not null, max_players integer not null, current_players integer default 1, status text default 'waiting', scheduled_start timestamptz not null, started_at timestamptz, ended_at timestamptz, duration_minutes integer not null, is_private boolean default false, invite_code text, is_premium_only boolean default false, entry_fee integer default 0, prize_xp integer default 100, allowed_categories text[], game_settings jsonb, allow_spectators boolean default false, spectator_count integer default 0, chat_room_id uuid, created_at timestamptz default now() ); create table competition_players ( competition_id uuid references competitions(id) on delete cascade, user_id uuid references users(id) on delete cascade, username text not null, avatar_url text, joined_at timestamptz default now(), score integer default 0, correct_answers integer default 0, wrong_answers integer default 0, streak integer default 0, is_host boolean default false, is_ready boolean default false, is_active boolean default true, last_active_at timestamptz, status text, primary key (competition_id, user_id) ); create table friends ( id uuid default uuid_generate_v4() primary key, user_id uuid references users(id) on delete cascade, friend_id uuid references users(id) on delete cascade, friend_username text not null, friend_display_name text, friend_avatar_url text, created_at timestamptz default now(), status text default 'pending', accepted_at timestamptz, is_favorite boolean default false, is_muted boolean default false, nickname text, last_interaction_at timestamptz, unique(user_id, friend_id) ); create table friend_requests ( id uuid default uuid_generate_v4() primary key, sender_id uuid references users(id) on delete cascade, sender_username text not null, sender_display_name text, sender_avatar_url text, receiver_id uuid references users(id) on delete cascade, created_at timestamptz default now(), status text default 'pending', message text, responded_at timestamptz ); create table conversations ( id uuid default uuid_generate_v4() primary key, participant1_id uuid references users(id) on delete cascade, participant2_id uuid references users(id) on delete cascade, created_at timestamptz default now(), updated_at timestamptz default now(), last_message_id uuid, unread_count_p1 integer default 0, unread_count_p2 integer default 0, is_archived_p1 boolean default false, is_archived_p2 boolean default false, is_muted_p1 boolean default false, is_muted_p2 boolean default false, participant1_deleted boolean default false, participant2_deleted boolean default false, unique(participant1_id, participant2_id) ); create table messages ( id uuid default uuid_generate_v4() primary key, conversation_id uuid references conversations(id) on delete cascade, sender_id uuid references users(id) on delete cascade, sender_username text not null, sender_avatar_url text, content text not null, created_at timestamptz default now(), is_read boolean default false, read_at timestamptz, is_deleted boolean default false, is_edited boolean default false, edited_at timestamptz, reply_to_message_id uuid references messages(id), reply_to_content text ); create table notifications ( id uuid default uuid_generate_v4() primary key, user_id uuid references users(id) on delete cascade, type text not null, title text not null, body text not null, created_at timestamptz default now(), is_read boolean default false, read_at timestamptz, is_archived boolean default false, data jsonb, image_url text, action_url text, sender_id uuid references users(id), sender_name text, sender_avatar_url text ); create table notification_preferences ( user_id uuid references users(id) on delete cascade primary key, game_invites boolean default true, friend_requests boolean default true, messages boolean default true, game_started boolean default true, game_ended boolean default true, achievements boolean default true, leaderboard boolean default true, daily_reminders boolean default true, app_updates boolean default true, promotional boolean default true, email_notifications boolean default true, push_notifications boolean default true, in_app_notifications boolean default true, updated_at timestamptz default now() ); create table subscriptions ( id uuid default uuid_generate_v4() primary key, user_id uuid references users(id) on delete cascade, tier text not null, start_date timestamptz default now(), expiry_date timestamptz not null, is_active boolean default true, will_renew boolean default false, platform text, transaction_id text, created_at timestamptz default now() ); create table game_invites ( id uuid default uuid_generate_v4() primary key, competition_id uuid references competitions(id) on delete cascade, inviter_id uuid references users(id) on delete cascade, inviter_name text not null, inviter_avatar_url text, invitee_id uuid references users(id) on delete cascade, created_at timestamptz default now(), status text default 'pending', responded_at timestamptz, competition_title text ); create table blocked_users ( id uuid default uuid_generate_v4() primary key, blocker_id uuid references users(id) on delete cascade, blocked_id uuid references users(id) on delete cascade, blocked_username text not null, blocked_avatar_url text, blocked_at timestamptz default now(), reason text, unique(blocker_id, blocked_id) ); create table user_courses ( id uuid default uuid_generate_v4() primary key, user_id uuid references users(id) on delete cascade, native_language text not null, native_language_name text not null, native_language_flag text not null, target_language text not null, target_language_name text not null, target_language_flag text not null, current_level integer default 1, total_xp integer default 0, progress double precision default 0.0, is_active boolean default false, created_at timestamptz default now(), last_accessed_at timestamptz default now(), unique(user_id, native_language, target_language) ); alter table users enable row level security; alter table competitions enable row level security; alter table competition_players enable row level security; alter table friends enable row level security; alter table friend_requests enable row level security; alter table conversations enable row level security; alter table messages enable row level security; alter table notifications enable row level security; alter table notification_preferences enable row level security; alter table subscriptions enable row level security; alter table game_invites enable row level security; alter table blocked_users enable row level security; alter table user_courses enable row level security; create index idx_competitions_status on competitions(status); create index idx_competitions_language on competitions(language); create index idx_friends_user_id on friends(user_id); create index idx_friend_requests_receiver on friend_requests(receiver_id); create index idx_messages_conversation on messages(conversation_id); create index idx_notifications_user on notifications(user_id, created_at desc); create index idx_game_invites_invitee on game_invites(invitee_id, status); create index idx_user_courses_user on user_courses(user_id, last_accessed_at desc); CREATE POLICY "Users can view their own courses" ON public.user_courses FOR SELECT USING (auth.uid() = user_id); CREATE POLICY "Users can insert their own courses" ON public.user_courses FOR INSERT WITH CHECK (auth.uid() = user_id); CREATE POLICY "Users can update their own courses" ON public.user_courses FOR UPDATE USING (auth.uid() = user_id); CREATE POLICY "Users can delete their own courses" ON public.user_courses FOR DELETE USING (auth.uid() = user_id); create or replace function update_updated_at_column() returns trigger as $$ begin new.updated_at = now(); return new; end; $$ language plpgsql; create trigger users_updated_at before update on users for each row execute function update_updated_at_column();